package kotlinx.coroutines.flow

import kotlinx.coroutines.*
import kotlin.test.*

class SharedFlowToListTest : TestBase() {
    @Test
    fun testSharedFlowToListWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 1)
        sharedFlow.emit(1)

        val acc = mutableListOf<Int>()
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toList(acc)
        }

        sharedFlow.emit(2)
        job.cancel()

        assertEquals(listOf(1, 2), acc)
    }

    @Test
    fun testSharedFlowToSetWithDestination() = runTest {
        val sharedFlow = MutableSharedFlow<Int>(replay = 1)
        sharedFlow.emit(1)

        val acc = mutableSetOf<Int>()
        val job = launch(start = CoroutineStart.UNDISPATCHED) {
            sharedFlow.toSet(acc)
        }

        sharedFlow.emit(2)
        job.cancel()

        assertEquals(setOf(1, 2), acc)
    }
}
"}

